const ALL_CITIES = [];
Object.entries(DESTINATIONS_DB).forEach(([continent, countries]) => {
  Object.entries(countries).forEach(([country, cities]) => {
    cities.forEach(city => ALL_CITIES.push({ city, country, continent }));
  });
});

