const SUPABASE_URL = "https://mfmhwaxokyfakmyizwqd.supabase.co";
const SUPABASE_KEY = "sb_publishable_5Qgwn27ebKyoCGqf-dMVMg_DCoNjtJ-";
const SB = {
  headers: { "Content-Type": "application/json", "apikey": SUPABASE_KEY, "Authorization": `Bearer ${SUPABASE_KEY}` },
  async saveBlob(table, key, data) {
    try {
      const h = { ...this.headers, "Prefer": "resolution=merge-duplicates" };
      // Check if row exists
      const chk = await fetch(`${SUPABASE_URL}/rest/v1/${table}?mes=eq.${encodeURIComponent(key)}&select=mes`, { headers: this.headers });
      const exists = await chk.json();
      if (exists && exists.length > 0) {
        // Update
        await fetch(`${SUPABASE_URL}/rest/v1/${table}?mes=eq.${encodeURIComponent(key)}`, {
          method: "PATCH",
          headers: h,
          body: JSON.stringify({ data: data, updated_at: new Date().toISOString() })
        });
      } else {
        // Insert
        await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
          method: "POST",
          headers: h,
          body: JSON.stringify({ mes: key, data: data, updated_at: new Date().toISOString() })
        });
      }
    } catch(e) { console.error("Supabase saveBlob error:", e); }
  },
  async loadBlob(table, key) {
    try {
      const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}?mes=eq.${encodeURIComponent(key)}&select=data`, { headers: this.headers });
      const rows = await r.json();
      return rows?.[0]?.data || null;
    } catch { return null; }
  }
};



