      ...newPago, id: Date.now(), monto: Number(newPago.monto),
      ventaId: data.ventaId || "", tipo: "proveedor",
      method: newPago.metodo, moneda: newPago.moneda,
      amount: Number(newPago.monto), date: newPago.fecha || new Date().toISOString().split('T')[0],
